{
  "mode": "method",
  "tests": [
    {
      "name": "test_signature_loading_inline_reply",
      "input": {
        "action": "reply",
        "inline": true,
        "add_in": "custom_signature_add_in"
      },
      "output": {
        "signature_loaded": true
      },
      "notes": "Validates that the custom signature loads correctly in an inline reply."
    },
    {
      "name": "test_signature_loading_pop_out_reply",
      "input": {
        "action": "reply",
        "inline": false,
        "add_in": "custom_signature_add_in"
      },
      "output": {
        "signature_loaded": true
      },
      "notes": "Ensures that the signature loads correctly when the compose window is popped out."
    },
    {
      "name": "test_signature_modification_triggers_alert",
      "input": {
        "action": "modify_signature",
        "add_in": "custom_signature_add_in",
        "modification": "added text"
      },
      "output": {
        "smart_alert_triggered": true
      },
      "notes": "Checks that modifying the signature triggers the Smart Alerts dialog."
    },
    {
      "name": "test_signature_modification_no_alert",
      "input": {
        "action": "modify_signature",
        "add_in": "custom_signature_add_in",
        "modification": "no change"
      },
      "output": {
        "smart_alert_triggered": false
      },
      "notes": "Validates that no alert is triggered when there is no modification."
    },
    {
      "name": "test_signature_loading_empty_reply",
      "input": {
        "action": "reply",
        "inline": true,
        "add_in": "custom_signature_add_in",
        "email_body": ""
      },
      "output": {
        "signature_loaded": false
      },
      "notes": "Tests behavior when replying to an empty email body."
    },
    {
      "name": "test_signature_loading_with_multiple_add_ins",
      "input": {
        "action": "reply",
        "inline": true,
        "add_ins": ["custom_signature_add_in", "another_add_in"]
      },
      "output": {
        "signature_loaded": true
      },
      "notes": "Ensures that the signature loads correctly when multiple add-ins are present."
    },
    {
      "name": "test_signature_modification_large_text",
      "input": {
        "action": "modify_signature",
        "add_in": "custom_signature_add_in",
        "modification": "large amount of text"
      },
      "output": {
        "smart_alert_triggered": true
      },
      "notes": "Validates that large modifications still trigger the Smart Alerts."
    },
    {
      "name": "test_signature_modification_special_characters",
      "input": {
        "action": "modify_signature",
        "add_in": "custom_signature_add_in",
        "modification": "special characters !@#$%^&*()"
      },
      "output": {
        "smart_alert_triggered": true
      },
      "notes": "Checks that modifying the signature with special characters triggers the alert."
    }
  ],
  "assumptions": "The add-in is properly installed and configured in Outlook.",
  "notes": "Tests should be run in a controlled environment to ensure consistent results."
}
